arguments.file_text:
namespace CheckoutWizard.Models;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

namespace CheckoutWizard.Services;

public interface IAddressValidator
{
    Task<bool> ValidateAddressAsync(string address, string city, string zip, CancellationToken ct);
}

@namespace CheckoutWizard.Components.Checkout
@using CheckoutWizard.Models

<h3>Checkout</h3>

<div class="checkout-wizard">
    @switch (_step)
    {
        case WizardStep.Shipping:
            <ShippingStep Shipping="@_order.Shipping"
                          OnNext="@HandleShippingComplete" />
            break;

        case WizardStep.Payment:
            <PaymentStep Payment="@_order.Payment"
                         OnBack="@HandleBackToShipping"
                         OnPlaceOrder="@HandlePlaceOrder" />
            break;
    }
</div>

@code {
    /// <summary>
    /// Fired when the user clicks "Place Order" on the final step,
    /// delivering the completed <see cref="Order"/> to the parent.
    /// </summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order _order = new();
    private WizardStep _step = WizardStep.Shipping;

    private void HandleShippingComplete()
    {
        _step = WizardStep.Payment;
    }

    private void HandleBackToShipping()
    {
        _step = WizardStep.Shipping;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }

    private enum WizardStep { Shipping, Payment }
}

@namespace CheckoutWizard.Components.Checkout
@using CheckoutWizard.Models
@using CheckoutWizard.Services
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="mb-3">
        <label class="form-label">Name</label>
        <input class="form-control" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address</label>
        <input class="form-control" @bind="Shipping.Address" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">City</label>
        <input class="form-control" @bind="Shipping.City" @bind:event="oninput" />
    </div>

    <div class="mb-3">
        <label class="form-label">Zip Code</label>
        <input class="form-control" @bind="Shipping.ZipCode" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_validationError))
{
    <div class="alert alert-danger mt-2">@_validationError</div>
}

<div class="mt-3">
    <button class="btn btn-primary" @onclick="HandleNextAsync" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    private async Task HandleNextAsync()
    {
        _validationError = null;

        // Cancel any in-flight validation (e.g. user went back, changed fields, clicked Next again).
        CancelPendingValidation();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address,
                Shipping.City,
                Shipping.ZipCode,
                token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was intentionally cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

@namespace CheckoutWizard.Components.Checkout
